const { execSync } = require('child_process');
const item = $input.item.json;
const cwd = 'c:/Users/veeramani/desktop/playwright-mcp';
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;

const startTime = new Date();
let stdout = '', stderr = '', exitCode = 0;
try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 600000 }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}

const duration = ((new Date() - startTime) / 1000).toFixed(2);
let testCases = [];
let stats = { total: 0, passed: 0, failed: 0 };
let reportSummary = '';

try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
      stats.passed = jsonData.stats.expected || 0;
      stats.failed = jsonData.stats.unexpected || 0;
      stats.total = stats.passed + stats.failed + (jsonData.stats.skipped || 0);
    }
    if (jsonData.suites) {
      jsonData.suites.forEach(suite => {
        (suite.specs || []).forEach(spec => {
          spec.tests.forEach(test => {
            const res = test.results && test.results[0];
            const status = res ? res.status : 'failed';
            testCases.push({ title: spec.title || 'Test', status: status, file: item.filename });
          });
        });
      });
    }
  }
} catch (e) {}

if (testCases.length === 0) {
    const status = exitCode === 0 ? 'passed' : 'failed';
    testCases.push({ title: 'Standard Execution', status: status, file: item.filename });
    stats.total = 1;
    if (status === 'passed') stats.passed = 1; else stats.failed = 1;
}

reportSummary = testCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title}`).join('\n');

return {
  json: { ...item, exitCode, status: exitCode === 0 ? 'passed' : 'failed', duration: `${duration}s`, stats, testCases, reportSummary }
};

