const fs = require('fs');
const path = require('path');
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';

const lockFile = path.join(resultsDir, 'summary.lock');
if (fs.existsSync(lockFile)) return []; 
fs.writeFileSync(lockFile, 'locked');

const files = fs.readdirSync(resultsDir).filter(f => f.startsWith('test_') && f.endsWith('.json'));
let totalScripts = files.length, totalCases = 0, passedCases = 0, product = 'ERP';
let allTestCases = [];

files.forEach(f => {
  const data = JSON.parse(fs.readFileSync(path.join(resultsDir, f)));
  product = data.product || product;
  if (data.testCases) {
    data.testCases.forEach(tc => {
      allTestCases.push({ ...tc, file: data.filename });
      totalCases++;
      if (tc.status === 'passed') passedCases++;
    });
  }
});

const successRate = totalCases > 0 ? ((passedCases / totalCases) * 100).toFixed(2) : 0;
const chatDetails = allTestCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title}`).join('\n');

return [{ json: { product, totalScripts, totalCases, passedCases, failedCases: totalCases - passedCases, successRate, allTestCases, chatDetails, timestamp: new Date().toLocaleString('en-GB') } }];
